+        }
+        drop(listener);
+        let mut all_data = Vec::new();
+        for mut s in servers {
+            let mut buf = Vec::new();
+            s.read_to_end(&mut buf).unwrap();
+            assert_eq!(buf.len(), 4);
+            all_data.push(buf[0]);
+        }
+        all_data.sort();
+        assert_eq!(all_data, vec![0, 1, 2]);
+        cleanup(&path);
+    }
